SeqType classifyProteinLikeAlphabet(std::vector<std::string> &sequences) {
    const double ALPHA = 0.1;
    const size_t MAX_SEQ = 20, MAX_ROW = 50, MAX_COL_SITES = 50, MAX_COL_PAIRS = 20;
    std::mt19937 rng((unsigned) Params::getInstance().ran_seed);   // inherit IQ-TREE seed: reproducible with -seed, random otherwise

    std::unordered_map<std::string,int> rowIdx, colIdx;
    for (int i = 0; i < NPAIR; i++) {
        if (clf_isrow[i]) rowIdx[clf_pairs[i]] = i; else colIdx[clf_pairs[i]] = i;
    }
    std::vector<double> counts(NPAIR, 0.0);

    // Row: sample up to 20 sequences; per sequence sample up to 50 valid doublets.
    std::vector<size_t> order(sequences.size());
    for (size_t i = 0; i < order.size(); i++) order[i] = i;
    std::shuffle(order.begin(), order.end(), rng);
    size_t nseq = std::min(order.size(), MAX_SEQ);
    for (size_t s = 0; s < nseq; s++) {
        const std::string &seq = sequences[order[s]];
        std::vector<int> pool;                 // feature index, or -1 if a valid AA doublet not in the set
        for (size_t j = 0; j + 1 < seq.size(); j++) {
            if (clfAaIndex(seq[j]) < 0 || clfAaIndex(seq[j+1]) < 0) continue;
            std::string p;
            p += (char)toupper((unsigned char)seq[j]);
            p += (char)toupper((unsigned char)seq[j+1]);
            std::unordered_map<std::string,int>::iterator it = rowIdx.find(p);
            pool.push_back(it != rowIdx.end() ? it->second : -1);
        }
        std::shuffle(pool.begin(), pool.end(), rng);
        size_t np = std::min(pool.size(), MAX_ROW);
        for (size_t k = 0; k < np; k++) if (pool[k] >= 0) counts[pool[k]] += 1.0;
    }

    // Column: sample up to 50 variant sites; per site sample up to 20 different-character taxa-pairs.
    size_t ncol = 0;
    for (size_t s = 0; s < sequences.size(); s++)
        if (sequences[s].size() > ncol) ncol = sequences[s].size();
    std::vector<size_t> sites;
    for (size_t c = 0; c < ncol; c++) {
        int seen[20]; for (int a = 0; a < 20; a++) seen[a] = 0;
        int distinct = 0;
        for (size_t s = 0; s < sequences.size(); s++) {
            if (c >= sequences[s].size()) continue;
            int a = clfAaIndex(sequences[s][c]);
            if (a >= 0 && seen[a] == 0) { seen[a] = 1; distinct++; }
        }
        if (distinct >= 2) sites.push_back(c);
    }
    std::shuffle(sites.begin(), sites.end(), rng);
    size_t nsite = std::min(sites.size(), MAX_COL_SITES);
    std::string pr; pr.resize(2);
    for (size_t si = 0; si < nsite; si++) {
        size_t c = sites[si];
        std::vector<int> chars;
        for (size_t s = 0; s < sequences.size(); s++) {
            if (c >= sequences[s].size()) continue;
            int a = clfAaIndex(sequences[s][c]);
            if (a >= 0) chars.push_back(a);
        }
        std::vector<std::pair<int,int> > pool;
        for (size_t i = 0; i < chars.size(); i++)
            for (size_t j = i + 1; j < chars.size(); j++)
                if (chars[i] != chars[j]) {
                    int a = chars[i] < chars[j] ? chars[i] : chars[j];
                    int b = chars[i] < chars[j] ? chars[j] : chars[i];
                    pool.push_back(std::make_pair(a, b));
                }
        std::shuffle(pool.begin(), pool.end(), rng);
        size_t npr = std::min(pool.size(), MAX_COL_PAIRS);
        for (size_t k = 0; k < npr; k++) {
            pr[0] = CLF_AA[pool[k].first]; pr[1] = CLF_AA[pool[k].second];
            std::unordered_map<std::string,int>::iterator it = colIdx.find(pr);
            if (it != colIdx.end()) counts[it->second] += 1.0;
        }
    }

    // pseudocount + per-block normalisation, then PCA projection
    double rowSum = 0.0, colSum = 0.0;
    for (int i = 0; i < NPAIR; i++) {
        counts[i] += ALPHA;
        if (clf_isrow[i]) rowSum += counts[i]; else colSum += counts[i];
    }
    if (rowSum <= 0.0 || colSum <= 0.0) return SEQ_PROTEIN;
    double pc[NPC];
    for (int k = 0; k < NPC; k++) pc[k] = 0.0;
    for (int i = 0; i < NPAIR; i++) {
        double f = counts[i] / (clf_isrow[i] ? rowSum : colSum);
        double z = (f - clf_center[i]) / clf_scale[i];
        for (int k = 0; k < NPC; k++) pc[k] += z * clf_rotation[i][k];
    }
    SeqType types[3] = {SEQ_PROTEIN, SEQ_3DI, SEQ_TEA};
    int best = 0; double bestd = -1.0;
    for (int t = 0; t < 3; t++) {
        double d = 0.0;
        for (int k = 0; k < NPC; k++) { double e = clf_centroid[t][k] - pc[k]; d += e*e; }
        if (bestd < 0.0 || d < bestd) { bestd = d; best = t; }
    }
    return types[best];
}
